import { PublicActionPage } from '@domain/publicActionPage';
import { AddressFieldProps } from '@pages/ActionPages/pages/ActionPagesBuilder/components/ActionPage/ActionPageForm/Fields/Address/Address';
import {
  useGetIsFreeTickets,
  useTotalAmount,
} from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks';
import { DonorProfileResponse as DonorProfile } from '@state/user/donor_profile';
import { FieldValues, FormState, UseFormTrigger, useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { useTicketTotalAmount } from 'src/builder/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks';
import { AddressSection } from './AddressSection';
import { ContactInfoSection } from './ContactInfoSection';
import { EmploymentSection } from './EmploymentSection';
import { LogoutSection, LogoutSectionProps } from './LogoutSection';
import { PaymentMethodSection } from './PaymentMethodSection';

type Props = Pick<AddressFieldProps, 'fieldPrefix' | 'fieldPrefixDelimiter'> &
  Pick<LogoutSectionProps, 'onLogout'> & {
    actionPage: PublicActionPage;
    donorProfile: DonorProfile;
    // These are used as debugging tools in prod. Exposing them as props will allow
    // investigation via the React Chrome extension so that the form state can be inspected
    formState?: FormState<FieldValues>;
    isEmbedded: boolean;
    trigger: UseFormTrigger<FieldValues>;
  };

export const SignedInControls = ({
  actionPage,
  donorProfile,
  fieldPrefix,
  fieldPrefixDelimiter,
  formState,
  isEmbedded,
  onLogout,
}: Props) => {
  const { watch } = useFormContext();
  const isFreeTickets = useGetIsFreeTickets(actionPage);
  const ticketAmount = useTicketTotalAmount(actionPage);
  const promoCodeDiscount = watch('promoCodeDiscount');
  const donationAmount = useTotalAmount();
  const totalAmount = donationAmount + ticketAmount - promoCodeDiscount;
  const { t } = useTranslation('actionPagesBuilder', { keyPrefix: 'public.validation' });
  const PHONE_INVALID_MESSAGE = t('phone.validity');

  return (
    <div className="mb-2 flex w-full flex-col gap-2">
      <div className="flex w-full flex-col gap-4 rounded-2xl border-2 border-neutral-200 px-0 py-4">
        <ContactInfoSection actionPage={actionPage} donorProfile={donorProfile} />
        <AddressSection
          actionPage={actionPage}
          donorProfile={donorProfile}
          fieldPrefix={fieldPrefix}
          fieldPrefixDelimiter={fieldPrefixDelimiter}
        />
        <EmploymentSection actionPage={actionPage} donorProfile={donorProfile} />
        {totalAmount > 0 && (
          <PaymentMethodSection
            actionPage={actionPage}
            donorProfile={donorProfile}
            isEmbedded={isEmbedded}
          />
        )}
      </div>
      {/* Only show with DonorID and when free tickets are selected and has address errors */}
      {/* Don't show address errors in DonorID: when the address is missing/invalid, */}
      {/* the address field in StandardFields will display with error(s). */}
      {formState?.errors && !!Object.keys(formState.errors).length && isFreeTickets ? (
        <div className="text-sm text-red-400">
          {Object.entries(formState?.errors).map(([key, value]) => {
            const keys = [
              'addressAttributes',
              'city',
              'country',
              'email',
              'employer',
              'employerCity',
              'employerCountry',
              'employerLine1',
              'employerPostalCode',
              'employerRegion',
              'firstName',
              'lastName',
              'line1',
              'line2',
              'middleInitial',
              'occupation',
              'phone',
              'postalCode',
              'region',
              'suffix',
            ];

            if (!keys.includes(key)) {
              return null;
            }

            if (key === 'phone') {
              // Only show error for invalid phone formats (e.g., "56565"), not for missing required values.
              // Legacy DonorIDs may have invalid phones, and we need to show the invalid error here since the Phone field
              // in StandardFields is only visible if there is no Phone value at all.
              if (value?.message === PHONE_INVALID_MESSAGE) {
                return <div key={PHONE_INVALID_MESSAGE}>{PHONE_INVALID_MESSAGE}</div>;
              }
            } else if (key === 'addressAttributes') {
              // @ts-ignore
              if (value?.postalCode) {
                // @ts-ignore
                return value?.postalCode?.message;
              } else {
                return null;
              }
            } else {
              if (value) {
                const message = value?.message ?? Object.values(value)[0]?.message;

                return <div key={message}>{message}</div>;
              }
            }

            return null;
          })}
        </div>
      ) : null}
      <LogoutSection onLogout={onLogout} />
    </div>
  );
};

